#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PF_PI 3.1415926535897932
#define PF_M 2147483647
#define PF_A 1103515245
#define PF_C 12345

inline double pf_roundDouble(double value) {
    int newValue = (int)(value);
    if (value - (double)newValue < 0.5)
        return (double)newValue;
    else
        return (double)newValue;
}

inline double pf_randu(__global int *seed, int index) {
    int num = PF_A * seed[index] + PF_C;
    seed[index] = num % PF_M;
    return fabs((double)seed[index] / (double)PF_M);
}

inline double pf_randn(__global int *seed, int index) {
    double u = pf_randu(seed, index);
    double v = pf_randu(seed, index);
    double cosine = cos(2.0 * PF_PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__kernel void likelihood_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *xj,
    __global double *yj,
    __global double *CDF,
    __global int *ind,
    __global int *objxy,
    __global double *likelihood,
    __global unsigned char *I,
    __global double *u,
    __global double *weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    __global int *seed,
    __global double *partial_sums,
    __local double *buffer)
{
    int x = (int)get_global_id(0);
    if (x >= Nparticles)
        return;

    double newX = xj[x] + 1.0 + 5.0 * pf_randn(seed, x);
    double newY = yj[x] + -2.0 + 2.0 * pf_randn(seed, x);

    arrayX[x] = newX;
    arrayY[x] = newY;

    int roundedX = (int)pf_roundDouble(newX);
    int roundedY = (int)pf_roundDouble(newY);

    double like = 0.0;
    int base = x * countOnes;

    for (int y = 0; y < countOnes; y++) {
        int indX = roundedX + objxy[y * 2 + 1];
        int indY = roundedY + objxy[y * 2];
        int idx = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (idx >= max_size)
            idx = 0;
        ind[base + y] = idx;

        double v100 = (double)((int)I[idx] - 100);
        double v228 = (double)((int)I[idx] - 228);
        like += (v100 * v100 - v228 * v228) / 50.0;
    }

    like = like / (double)countOnes;
    likelihood[x] = like;

    weights[x] = weights[x] * exp(like);
    partial_sums[x] = weights[x];

    (void)CDF;
    (void)u;
    (void)buffer;
}

