#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void find_index_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *CDF,
    __global double *u,
    __global double *xj,
    __global double *yj,
    __global double *weights,
    int Nparticles)
{
    if (get_global_id(0) != 0)
        return;

    for (int j = 0; j < Nparticles; j++) {
        int i;
        int index = -1;
        double value = u[j];

        for (i = 0; i < Nparticles; i++) {
            if (CDF[i] >= value) {
                index = i;
                break;
            }
        }

        if (index == -1)
            index = Nparticles - 1;

        xj[j] = arrayX[index];
        yj[j] = arrayY[index];
    }

    for (int j = 0; j < Nparticles; j++) {
        arrayX[j] = xj[j];
        arrayY[j] = yj[j];
        weights[j] = 1.0 / (double)Nparticles;
    }
}
